const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'sql-default').trim();
const history = body.history || [];

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

if (message.length > 10000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 10000 символов)'}}];
}

let historyContext = '';
if (history.length > 0) {
  const lines = history.slice(-10).map(m => {
    const role = m.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (m.content || m.text || '').substring(0, 300);
  });
  historyContext = 'История диалога:\n' + lines.join('\n') + '\n\n';
}

return [{json: {valid: 1, message: message, session_id: session_id, historyContext: historyContext}}];

const message = $input.first().json.message;
const historyContext = $input.first().json.historyContext || '';
const session_id = $input.first().json.session_id || 'sql-default';
const lower = message.toLowerCase();

const sqlKeywords = [
  'покажи', 'выведи', 'список', 'найди клиент', 'найди заказ',
  'клиент', 'заказ', 'заказы', 'выручк', 'revenue',
  'таблиц', 'запрос', 'база данных', 'бд', 'базу',
  'select', 'insert', 'update', 'delete', 'sql',
  'добавь', 'удали', 'измени', 'обнови',
  'сколько клиентов', 'сколько заказов', 'сколько записей',
  'статус', 'pending', 'delivered', 'cancelled',
  'город', 'москва', 'питер', 'петербург',
  'email', 'выручка', 'сумма заказ', 'средн',
  'группир', 'сортир', 'отсортируй', 'отфильтруй', 'фильтр',
  'топ ', 'top ', 'первые', 'последние',
  'join', 'объедин', 'связ',
  'аналитик', 'статистик', 'отчёт', 'отчет',
  'за период', 'за месяц', 'за год', 'за неделю',
  'больше чем', 'меньше чем', 'равно',
  'максимальн', 'минимальн', 'итого'
];

let isSQL = false;

for (const kw of sqlKeywords) {
  if (lower.includes(kw)) { isSQL = true; break; }
}

// Если упоминаются данные и есть вопросительный характер
if (!isSQL && message.length > 15) {
  const dataIndicators = ['сколько', 'какие', 'кто', 'где', 'когда', 'чей', 'чья'];
  const dataEntities = ['клиент', 'заказ', 'товар', 'продукт', 'запис', 'строк'];
  const hasQuestion = dataIndicators.some(q => lower.includes(q));
  const hasEntity = dataEntities.some(e => lower.includes(e));
  if (hasQuestion && hasEntity) isSQL = true;
}

if (!isSQL) {
  return [{ json: { message, mode: 'general', historyContext, session_id } }];
}

return [{ json: { message, mode: 'sql', historyContext, session_id } }];

