try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{json: {query: "SELECT 'GigaChat недоступен. Попробуйте позже.' as error_message;"}}];
  }

  let sql = raw.output[0].content[0].text;

  // Убираем markdown
  sql = sql.replace(/```sql\s*/gi, '').replace(/```\s*/g, '').trim();

  // Находим начало SQL
  const match = sql.match(/\b(SELECT|INSERT|UPDATE|DELETE|WITH|CREATE|ALTER|DROP|TRUNCATE)\b/i);
  if (match && match.index > 0) {
    sql = sql.substring(match.index);
  }

  // Чистим хвост
  sql = sql.replace(/;\s*$/, ';');
  if (!sql.endsWith(';')) sql += ';';

  // Блокируем опасные DDL/DCL
  const firstWord = sql.trim().split(/\s+/)[0].toUpperCase();
  const BLOCKED = ['DROP', 'TRUNCATE', 'ALTER', 'GRANT', 'REVOKE', 'CREATE'];
  if (BLOCKED.includes(firstWord)) {
    return [{json: {query: "SELECT '" + firstWord + " заблокирована в целях безопасности' as error_message;"}}];
  }

  // DELETE/UPDATE без WHERE — массовая операция, блокируем
  if ((firstWord === 'DELETE' || firstWord === 'UPDATE') && !/\bWHERE\b/i.test(sql)) {
    return [{json: {query: "SELECT '" + firstWord + " без WHERE заблокирован: затронет все строки. Уточните условие.' as error_message;"}}];
  }

  // Авто-LIMIT
  if (/^\s*SELECT/i.test(sql) && !/\bLIMIT\b/i.test(sql)) {
    sql = sql.replace(/;\s*$/, '') + ' LIMIT 50;';
  }

  return [{json: {query: sql}}];

} catch(e) {
  return [{json: {query: "SELECT 'Не удалось сгенерировать SQL. Переформулируйте вопрос.' as error_message;"}}];
}

